function fetch_carton_items_server(frm) {
    // Collect all carton names from the table
    let cartons = (frm.doc.carton || []).map(d => d.carton).filter(d => d);

    if (cartons.length > 0) {
        frappe.call({
            method: "pos_ar.pos_ar.doctype.brand_based_inventory.brand_based_inventory.get_items_from_cartons", // e.g., "myapp.myapp.doctype.brand_based_inventory.brand_based_inventory.get_items_from_cartons"
            args: {
                cartons: cartons
            },
            callback: function(r) {
                if (r.message) {
                    console.log("r ::: " , r.message)
                    frm.clear_table("carton_items");
                    r.message.forEach(item => {
                        let row = frm.add_child("carton_items");
                        row.item = item.item;
                        row.carton = item.carton_origin;
                        row.qty = item.qty;
                        // row.custom_field = item.carton_origin; 
                    });
                    frm.refresh_field("carton_items");
                }
            }
        });
    } else {
        frm.clear_table("carton_items");
        frm.refresh_field("carton_items");
    }
}


// Reusable filter function
function set_carton_filters(frm) {
    // 1. Filter the main Warehouse field
    frm.set_query("warehouse", function() {
        return {
            filters: { "company": frm.doc.company }
        };
    });

    // 2. Filter the 'carton' link field inside the 'carton' child table
    // The first "carton" is the field name inside the child row
    // The second "carton" is the table field name in the parent
    frm.set_query("carton", "carton", function() {
        return {
            filters: { 
                "company"  : frm.doc.company,
                "warehouse": frm.doc.warehouse,
                "status"   : "Closed"
                }
        };
    });
}

















































