function fetch_items_by_brand_by_server(frm) {
    let brands = (frm.doc.brand || []).map(d => d.brand).filter(d => d);

    if (brands.length > 0 && frm.doc.warehouse) {
        frappe.call({
            method: "pos_ar.pos_ar.doctype.brand_based_inventory.brand_based_inventory.get_items_by_brand",
            args: {
                brands: brands,
                warehouse: frm.doc.warehouse
            },
            callback: function(r) {
                if (r.message) {
                    frm.clear_table("items");

                    // 1. Update the Brand Child Table with counts
                    // r.message.brands looks like {"Brand1": 5, "Brand2": 12}
                    Object.keys(r.message.brands).forEach(brand_name => {
                        let count = r.message.brands[brand_name];
                        console.log("the brand ==> " , brand_name , "the count ==> " , count)
                        let brand_row = (frm.doc.brand || []).find(d => d.brand === brand_name);
                        
                        if (brand_row) {
                            // Update the count field (assumed field name is 'items_count')
                            frappe.model.set_value(brand_row.doctype, brand_row.name, "items", count);
                        }
                    });

                    // 2. Update the Items Child Table
                    // r.message.items looks like {"item1": {"brand": "b1", "actual_qty": 10}}
                    Object.keys(r.message.items).forEach(item_code => {
                        let data = r.message.items[item_code];
                        let row = frm.add_child("items");
                        
                        row.item = item_code; // or row.item depending on your fieldname
                        row.actual_qty = data.actual_qty;
                        row.brand = data.brand;
                    });

                    frm.refresh_field("items");
                    frm.refresh_field("brand");
                }
            }
        });
    } else {
        frm.clear_table("items");
        frm.refresh_field("items");
    }
}
/**
 * Sums up all gaps for items belonging to a specific brand 
 * and updates the 'gap' field in the 'brand' child table.
 */
function calculate_brand_totals(frm, brand_name) {
    if (!brand_name) return;

    // 1. Calculate the sum of gaps for all items belonging to this brand
    let total_brand_gap = 0;
    let total_brand_item_qty = 0 ;
    (frm.doc.items || []).forEach(item => {
        if (item.brand === brand_name) {
            total_brand_gap += flt(item.gap);
            total_brand_item_qty += flt(item.total)
        }
    });

    // 2. Find the row in the 'brand' table and update it
    let brand_row = (frm.doc.brand || []).find(d => d.brand === brand_name);
    if (brand_row) {
        // Replace 'gap' with the actual field name in your Brand child table
        frappe.model.set_value(brand_row.doctype, brand_row.name, "gap", total_brand_gap);
        frappe.model.set_value(brand_row.doctype, brand_row.name, "gap_percentage", total_brand_gap*100/total_brand_item_qty);
        frm.refresh_field("brand");
    }
}



