/**
 * Calculates total = q1 + q2 + q3 + q4 for a specific row
 */
function calculate_row_total_and_dif(frm, cdt, cdn) {
    let row = locals[cdt][cdn];
    
    // Ensure values are treated as numbers, defaulting to 0 if empty
    let q1 = flt(row.q1);
    let q2 = flt(row.q2);
    let q3 = flt(row.q3);
    let q4 = flt(row.q4);
    
    let total = q1 + q2 + q3 + q4;
    
    let dif = flt(row.actual_qty) - total
    let gap = dif
    if(gap < 0){
        gap = gap * -1
    }
    // Update the 'total' field in the current child table row
    frappe.model.set_value(cdt, cdn, 'total', total);
    frappe.model.set_value(cdt, cdn, 'dif', dif);
    frappe.model.set_value(cdt, cdn, 'gap', gap);
    
    calculate_brand_totals(frm, row.brand)
}

