function calculer_ecart(frm, cdt, cdn) {
    let row = locals[cdt][cdn];

    let total =
        flt(row.qte_1) +
        flt(row.qte_2) +
        flt(row.qte_3) +
        flt(row.qte_4);

    row.total = total;
    row.ecart = total - flt(row.qte_facturee);

    frm.refresh_field("articles");

    // Mise en couleur si écart
    setTimeout(() => {
        let grid_row = frm.fields_dict["articles"]
            .grid.grid_rows_by_docname[cdn];

        if (!grid_row) return;

        grid_row.row.style.backgroundColor =
            (row.ecart !== 0) ? "#ffe6e6" : "";
    }, 50);
}

