function update_items_from_ctns(frm) {
    
    
    const is_receipt = frm.doc.stock_entry_type === "Material Receipt";
    
    if(frm.doc.custom_carton_table.length == 0){
        frm.clear_table("items");
	    frm.refresh_field("items");
    }
    
	if (!frm.doc.custom_transfer_by_carton || !frm.doc.custom_carton_table.length) return;

	frm.clear_table("items");
	frm.refresh_field("items");

    const ctn_names = frm.doc.custom_carton_table.map(row => row.carton)


    console.log("the =>>>> " , ctn_names)
    
    frappe.call({
        method : "ctn_tracking_app.api.get_items_from_ctns",
        args : { ctn_list : ctn_names},
        freeze : true,
        freeze_message : "Fetching items from CTNs ...",
        callback : function(r){
            if(!r.message) return;
            frm.clear_table("items");
            r.message.forEach(item => {
                frm.add_child("items" , {
                    item_code         : item.item_code,
                    qty               : item.qty ,
                    uom               : item.uom || "",
                    stock_uom         : item.uom || "",
                    transfer_qty      : item.qty * item.conversion_factor,
                    conversion_factor : item.conversion_factor || 1 ,
                    s_warehouse       : is_receipt ? "" :item.s_warehouse,
                    t_warehouse       : frm.doc.to_warehouse //default to warhouse on issue just dont set it.
                })
            })
            
            frm.refresh_field("items");
            frappe.show_alert("Items updated from CTNs")
        }
    })

}



// Reusable filter function
function set_carton_filters(frm) {
    console.log("we are here : " , frm.doc.company)
    // 1. Filter for the main Warehouse field (as you already had)
    frm.set_query("from_warehouse", function() {
        return {
            filters: { "company": frm.doc.company }
        };
    });

    // 2. Filter the 'carton' field INSIDE the Child Table 'custom_carton_table'
    frm.set_query("carton", "custom_carton_table", function(doc, cdt, cdn) {
        return {
            filters: {
                //Only show cartons belonging to the selected company
                "company": frm.doc.company,
            }
        };
    });
}

